import{_ as r,o as n,c as e,a7 as o}from"./chunks/framework.BgApuQ2e.js";const p="/images/everything-dont-know-tipping/fire-and-ice-1024x628.png",a="/images/everything-dont-know-tipping/undertip-1.png",i="/images/everything-dont-know-tipping/undertip-3-1024x365.png",s="/images/everything-dont-know-tipping/undertip-4.png",g="/images/everything-dont-know-tipping/overtip-1.png",l="/images/everything-dont-know-tipping/overtip-2.png",h="/images/everything-dont-know-tipping/overtip-3.png",f="/images/everything-dont-know-tipping/standoff-1.png",c="/images/everything-dont-know-tipping/standoff-2.png",m="/images/everything-dont-know-tipping/standoff-3.png",d="/images/everything-dont-know-tipping/standoff-4.png",w="/images/everything-dont-know-tipping/standoff-5.png",u="/images/everything-dont-know-tipping/standoff-6.png",_="/images/everything-dont-know-tipping/standoff-7.png",y="/images/everything-dont-know-tipping/standoff-8.png",b="/images/everything-dont-know-tipping/TABLE-final-3.png",k="/images/everything-dont-know-tipping/Budget-Chart-final.png",v="/images/everything-dont-know-tipping/Demographic-chart1.png",T="/images/everything-dont-know-tipping/pinit_fg_en_rect_gray_20.png",E=JSON.parse(`{"title":"Everything You Don't Know About Tipping","description":"","frontmatter":{"title":"Everything You Don't Know About Tipping","titleZh":"关于小费你所不知道的一切","date":"2014-04-02T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2014/04/everything-dont-know-tipping.html","slug":"everything-dont-know-tipping"},"headers":[],"relativePath":"posts/everything-dont-know-tipping.md","filePath":"posts/everything-dont-know-tipping.md","lastUpdated":1782886257000}`),B={name:"posts/everything-dont-know-tipping.md"};function M(D,t,A,S,L,C){return n(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="关于小费你所不知道的一切-·-everything-you-don-t-know-about-tipping" tabindex="-1">关于小费你所不知道的一切 · Everything You Don&#39;t Know About Tipping <a class="header-anchor" href="#关于小费你所不知道的一切-·-everything-you-don-t-know-about-tipping" aria-label="Permalink to &quot;关于小费你所不知道的一切 · Everything You Don&#39;t Know About Tipping&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2014/04/everything-dont-know-tipping.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2014/04/everything-dont-know-tipping.html</a> · 2014-04-02</p></blockquote><h2 id="本文最初发表于-2014-年-4-月。" tabindex="-1"><em>本文最初发表于 2014 年 4 月。</em> <a class="header-anchor" href="#本文最初发表于-2014-年-4-月。" aria-label="Permalink to &quot;*本文最初发表于 2014 年 4 月。*&quot;">​</a></h2><p>小费不是关于慷慨。小费不是关于对优质服务的感激。小费也当然不是关于对你的同胞做正确和公平的事。</p><p>小费是关于确保你别把你应该做的事搞砸。</p><p>就我而言,故事是这样的:</p><p>大学时,我在一家叫 Fire and Ice 的怪餐厅当服务员。这是他们网站的首页(顺便一提,那些蹩脚的文字标签是网站上原本就有的,不是我加的):</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/fire-and-ice.png" target="_blank" rel="noreferrer"><img src="'+p+'" alt="fire and ice"></a></strong></p><p>后面那个悲伤的家伙是其中一位服务员。他悲伤是因为他没有工资,和其他所有服务员一样靠小费生活,但客人们给他的小费太少,因为在这家餐厅顾客要自己去拿食物,所以他们觉得他不是真正的服务员,即使他还得给他们端所有的饮料和配菜,还得像小丑一样给他们完整介绍餐厅和餐厅的运作方式,然后还得收拾桌子,因为餐厅没有杂工,而当他最不需要的就是经理们是些恶毒又强势、专门欺负他的中年女人时,这也偏偏发生了。</p><p>糟糕的人生经历先放一边,更大的重点是,我从服务员生涯中走出来时成了一个非常慷慨的小费给予者,就像所有做过涉及小费工作的人一样。我的朋友们有时会注意到这一点,说出诸如「Tim 是个给小费很大方的人」这样的话。我的自尊心很喜欢这些话,而现在,十年后,我把自己精准定位在了「大方但不至于夸张地大方的小费给予者」这一类别里。</p><p>所以每当出现给小费的场合,我脑子里想的都是:「一个大方但不至于夸张地大方的小费给予者在这里会怎么做?」</p><p>有时候我完全知道那个问题的答案,事情就顺顺利利。但其他时候,我发现自己陷入了可怕的<strong>小费歧义局面</strong>。<a href="#footnote-1-1377">1</a></p><p>小费歧义局面可能导致各种各样的灾难:</p><p><strong>1) 无意的少给</strong></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/undertip-1.png" target="_blank" rel="noreferrer"><img src="'+a+'" alt="Bar 1"></a></strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/undertip-3.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt="Bar 3"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/undertip-4.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt="Bar 4"></a></p><p><strong>2) 无意的多给</strong></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/overtip-1.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt="Delivery 1"></a></strong></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/overtip-2.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt="Delivery 2"></a></strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/overtip-3.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt="Delivery 3"></a></p><p><strong>3) “我他妈到底该不该给小费?”的惊悚瞬间</strong></p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/standoff-1.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt="Matzo 1"></a></strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/standoff-2.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt="Matzo 2"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/standoff-3.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt="Matzo 3"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/standoff-4.png" target="_blank" rel="noreferrer"><img src="'+d+'" alt="Matzo 4"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/standoff-5.png" target="_blank" rel="noreferrer"><img src="'+w+'" alt="Matzo 5"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/standoff-6.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt="Matzo 6"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/standoff-7.png" target="_blank" rel="noreferrer"><img src="'+_+'" alt="Matzo 7"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/standoff-8.png" target="_blank" rel="noreferrer"><img src="'+y+'" alt="Matzo 8"></a></p><p>我不想再这样活下去了。所以这一周,我决定采取行动。</p><p>我戴上了「怪但真诚地在做某项调查的男人」的帽子,走上街头,采访了 123 位在纽约从事与小费相关工作的人。我的采访对象包括服务员、调酒师、咖啡师、美甲师、理发师、餐厅杂工、门童、代客泊车员、门房、出租车司机、餐厅外卖员,甚至还有一些不收小费但我搞不懂为什么不收的人,比如针灸师和牙科保洁员。<a href="#footnote-2-1377">2</a> 我覆盖了纽约的多个片区,包括 SoHo、下东区、哈莱姆、上东区和金融区,试图涵盖尽可能广的范围——从最高档的地方到最破的小店。</p><p>大约 10% 的采访在七秒钟后就结束了,因为对方对我的出现感到不悦,我只好慢慢退出房间。但绝大多数人都很乐意跟我聊小费的事——收多少、多久收一次、不同客户群体之间差别多大、小费在他们收入里占多大比例等等——事实证明,服务业从业者对这个话题真是有一肚子话要说。</p><p>我还借助了大量读者发来的详细亲身经历,以及大量的研究资料,尤其是小费研究领域顶尖专家 Wm. Michael Lynn 的<a href="http://tippingresearch.com/index.html" target="_blank" rel="noreferrer">网站</a>。</p><p>好了,现在我对这事儿懂了。情况是这样的——</p><p><strong>给别人小费之前你需要知道的事:</strong></p><p><strong>数据篇</strong></p><p>避免「小费模糊瞬间」最关键的一步,就是搞清楚你到底该做什么。我把所有看起来共识度比较高的数据<a href="#footnote-3-1377">3</a>整理成了下面这张表:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/TABLE-final-3.png" target="_blank" rel="noreferrer"><img src="'+b+'" alt="Tipping Statistics"></a></p><p>这张表格很好地补上了我之前认知里的关键空白。上面用到的低/平均/高小费档位的基本思路是:如果你落在平均区间,就一切正常,没人会记得你。但如果你落在低档或高档区间,你就会被注意到、被记住。而服务业工作者的记性堪比大象。</p><p><strong>给小费给得慷慨(或不慷慨)对你的预算意味着什么</strong></p><p>既然给小费是生活里这么大的一部分,那我们似乎应该停下来实际算算——当一个低小费、平均小费或高小费给主,对你的预算到底意味着什么。</p><p>简单看的话,你可以快速算一下,搞清楚预算的一部分。比如说,你觉得自己一年吃 100 顿餐馆,每顿大约 25 美元——那么根据上面的图表,一整年做低档、平均、高档餐馆小费给主,分别会花你 350 美元(14% 小费)、450 美元(18% 小费)和 550 美元(22% 小费)。所以在这个例子里,从低档变成平均档一年多花 100 美元,从平均档变成高档档也是一年多花 100 美元。</p><p>我做得更全面了一点,搞出了三个粗略的画像:低消费者、中消费者、高消费者。这三类人的差别既在于他们去餐馆、酒吧、酒店等等的<strong>频率</strong>,<em>也</em>在于他们去的地方的档次——也就是说,高消费者常常去高档餐厅,低消费者出去吃得少而且去的地方更便宜。<a href="#footnote-4-1377">4</a> 我这么分是为了覆盖两个极端和中间——你大概率介于这三者之间某处。</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/Budget-Chart-final.png" target="_blank" rel="noreferrer"><img src="'+k+'" alt="Tipping Budgets"></a></strong><br><strong>其他应该影响具体给小费决定的因素</strong></p><p>我的采访清楚地表明了一件事:有一整组和情境相关的因素,服务业工作者觉得跟你该给多少小费超级相关——只是顾客从来没收到过这份备忘录。大多数顾客脑子里都有个标准小费数额,除此之外基本不多想。以下是服务业工作者希望你在给他们小费时不要再&quot;不考虑&quot;的东西:</p><p>**时间很重要。**有时候酒保啪地打开八瓶啤酒,花了 12 秒;有时候她要调八杯多种原料的鸡尾酒,每杯上面还得配橄榄和一整套小雨伞装饰,得花四分钟——即使这两单价钱可能一样,小费也不该一样给。同样的道理——</p><p>**付出的努力很重要。**外卖员的小费通常给得太少了——他们其实就像服务员,只不过你的餐桌在城市的另一头。2 美元真的不够(我采访过的一个外卖员说,20% 的人一分钱都不给)——3 或 4 美元会好得多。那外面下暴雨的时候呢?我采访的所有外卖员都说,恶劣天气下小费并不会变多——这不合逻辑。同样,外带订单给小费虽然不是必须的,但很贴心。一位餐厅经理跟我吐槽说,花旗银行每周订 35 份外带午餐,某个服务员要花很长时间来打包(汤要小心地包好、咖啡要用橡皮筋绑好、调料和佐料要装进小盒子里),却从来不给小费。付出的努力很重要,理应给小费。</p><p>**他们的工资水平很重要。**在美国,我们多少有点武断地把某些职业划为「靠小费的职业」,由顾客而不是雇主来负责支付这些从业人员的工资——这可能听起来没什么道理,但事实就是如此。因此,当为你服务的是一位「靠小费的职业」的从业人员时,你身上背负着一份别的场合没有的真实责任。</p><p>给咖啡师小费很棒,但你不给也不算什么坏人,毕竟人家没你也照样有工资拿。但服务员和调酒师就不一样了,他们的时薪在 2 到 5 美元之间(通常更接近 2 美元),而且这部分工资通常全部拿去交税了。你的小费真的就是他们的全部收入。他们还得给其他员工「分小费」,所以你给服务员小费的时候,其实也在给杂工、调酒师等人小费。因此,即使你讨厌那次服务,小费也绝对不能低于 15%。碰上糟糕服务的处理方式是像在不给小费的场合那样去向经理投诉——你没有资格靠扣小费来让他们白干活。</p><p>**服务本身很重要。**这一条听起来像废话,似乎不用说,但 Michael Lynn 的<a href="http://tippingresearch.com/uploads/Commentary_on_Bodvarsson.pdf" target="_blank" rel="noreferrer">研究</a>表明,人们给的小费金额和他们享受到的服务质量几乎没什么关系。<a href="#footnote-5-1377">5</a> 所以,虽然不给小费不行,但脑子里最好有一个「区间」而不是一个固定百分比,因为好的服务理应比差的服务拿到更高的小费。</p><p><strong>另外 11 个有趣的发现和事实:</strong></p><p><strong>1) 不同人群给小费的方式确实存在明显差异</strong></p><p>「不同人群——年龄、性别、种族、国籍、性取向、宗教、职业——给小费的方式是否不同?」这个问题在我的采访中以压倒性优势拿下了「最令人尴尬的问题」奖,但它带来了一些非常有意思的信息。我只把至少听到三次的观点当回事,而且在这篇文章里,我只收录那些能被我的网上调研和 Lynn 的统计研究证实的观点。</p><p>下面是概览,这是 Lynn 对 1000 多名服务员进行调查的结果可视化。<a href="#footnote-6-1377">6</a> 在下图中,每一类顾客都被放在他们在这项针对 1000+ 服务员调查中的平均评分位置上:</p><p><strong><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/Demographic-chart1.png" target="_blank" rel="noreferrer"><img src="'+v+'" alt="Who Tips the Best?"></a></strong></p><p>既迷人又尴尬。在我的整个采访过程中,我听到了很多印证这张图表的意见,几乎没有相反的。人们最容易关注的一点是外国人是糟糕的小费给予者,因为 A)这不算真正的人口统计学类别,所以没那么尴尬;B)如果人们不想显得刻薄,可以把这归咎于他们「不懂规矩」。不过,也有人对此嗤之以鼻,说:「哦他们懂……」在外国人当中,法国人名声最差。</p><p>人们还一致表示,那些表现得「自命不凡」或「挑剔」或「一副全世界都跟他过不去的样子」的人,通常都是糟糕的小费给予者。</p><p>在慷慨给小费的一边,度假的人或喝醉的人(或两者兼有)都给得不错,「熟客」——也就是跟员工混熟的那些人——也给得不错,当然,大家一致公认的最慷慨的小费给予者,就是那些同样在服务行业工作的人(说实话,采访到最后这让我有点毛骨悚然——他们对于彼此之间要慷慨给小费这件事,有一种邪教般诡异的执着)。</p><p><strong>2)以下是六种经过验证的服务员增加小费的方法:</strong></p><ul><li><ul><li>跟顾客是相反的性别</li><li>最理想的是,30 多岁、身材苗条、漂亮、大胸的金发女郎 <a href="#footnote-7-1377">7</a></li><li>自报姓名做自我介绍</li><li>点单时坐在桌边或蹲在旁边</li><li>触碰顾客,以一种不猥琐的方式 <a href="#footnote-8-1377">8</a></li><li>送账单的时候给顾客糖果 <a href="#footnote-9-1377">9</a></li></ul></li></ul><p>这些当然管用。人类很简单。</p><p><strong>3)几个不同的人都说,当小费很低时,他们会假设顾客小气或手头紧,但当小费很高时,他们会假设是因为自己服务做得很好,或因为自己讨人喜欢(而不是顾客慷慨)。</strong></p><p>**4)当一个男人给一位漂亮女性一笔巨额小费时,并不会让她觉得他有钱、慷慨或是大人物——只会让她觉得他在试图讨好她。**非常明显且没什么效果,但她很乐意收下这些额外的钱。</p><p><strong>5)如果处于不需要给小费的场景,别在小费栏里填零——这显然会让人觉得刻薄且没必要。留空并直接写上总额就行。</strong></p><p>**6)据代客泊车员和门童说,人们给他们小费时,几乎总是会做一个「双折」动作——把钞票对折两次,然后数字朝下递给他们,这样小费的金额就被藏起来了。**然而,当有人给一笔特别丰厚的小费时,他们通常会不折叠地把钞票递过去,而且金额朝上露在外面。</p><p><strong>7) 关于上面没提到的其他小费职业的一些说明:</strong></p><ul><li>显然没人给<strong>空乘</strong>小费,如果你给了,之后大概率会收到免费饮料。</li><li><strong>高尔夫球童</strong>说,高尔夫球员打得越好,给的小费就越多,但只要是在客户面前打球,给的小费永远最丰厚。</li><li><strong>纹身师</strong>期望 100 美元的活儿收到 10-20 美元,400 美元的活儿收到 40-60 美元,但有 30% 的人一毛不给。</li><li><strong>按摩师</strong>期望 15-20 美元的小费,95% 的情况下都能拿到——按摩师大约一半的收入来自小费。</li><li>一位<strong>激流漂流向导</strong>说,当筏子翻了或者发生了让人觉得有生命危险的事之后,他总能拿到最好的小费。</li><li><strong>脱衣舞娘</strong>不仅通常没有工资,而且经常是负工资——也就是说,她们得付给俱乐部一笔费用才能在那儿工作。</li></ul><p><strong>8) 根据 Lynn 的数据,美国每年的小费总额高达 400 亿美元。这是 NASA 预算的两倍多。</strong></p><p>**9) 美国是全世界最痴迷小费的国家,但其他国家的小费习俗五花八门。**小费专家 Magnus Thor Torfason 的研究显示,美国有 31 种服务行业涉及小费。这个数字在加拿大是 27,印度 27,荷兰 15,整个斯堪的纳维亚地区 5-10,日本 4,冰岛 0。</p><p><strong>10) 一个国家的小费规模往往与该国的腐败程度相关。<a href="#footnote-10-1377">10</a></strong> 即便控制了国家 GDP 和犯罪率等因素,这一相关性依然成立。理论上讲,鼓励小费的那套规范最终会渗透到其他形式的交易中。美国腐败程度相对较低,并不符合这一总体相关性。</p><p><strong>11) 名人应该给丰厚的小费,因为收到小费的人会永远逢人便说,而听说的每个人也都会永远逢人便说。</strong></p><p>举个例子:我一个朋友在圣莫尼卡一家叫 Cafe Montana 的高档午餐店服务过阿诺·施瓦辛格 (Arnold Schwarzenegger) 一家。因为他是州长,餐厅免了他的餐费。而他留下的小费是——5 美元。这故事我跟很多人讲过。</p><ul><li><p>**以慷慨小费闻名的名人(这些名字在相关文章里反复出现)😗*约翰尼·德普 (Johnny Depp)、查尔斯·巴克利 (Charles Barkley)、大卫·莱特曼 (David Letterman)、比尔·默瑞 (Bill Murray)、查理·辛 (Charlie Sheen)、德鲁·巴里摩尔 (Drew Barrymore)</p></li><li><p>**以吝啬小费闻名的名人:**老虎·伍兹 (Tiger Woods)、玛丽亚·凯莉 (Mariah Carey)、勒布朗·詹姆斯 (LeBron James)、海蒂·克鲁姆 (Heidi Klum)、比尔·考斯比 (Bill Cosby)、麦当娜 (Madonna)、芭芭拉·史翠珊 (Barbara Streisand)、瑞秋·雷 (Rachael Ray)、西恩·潘 (Sean Penn)、亚瑟小子 (Usher)</p></li></ul><p>最后我想说,这一周深入研究下来,有件事已经很清楚了:当一个抠门的小费给予者是件坏事。别当抠门的小费给予者。至于是给普通水平还是高水平,那就是个人选择了,取决于你想把手里那点用于慈善的钱花到哪儿。做个普通水平的给小费者、把慷慨留给别的地方,并没什么可羞愧的,但我想说,每年多花 200、500 或 1500 美元(取决于你的消费水平)升级成高水平的给小费者,是一笔相当划算的慈善支出。在小费的世界里,每一美元都意义重大。</p><hr><p><strong>其他帮你应对人生的 Wait But Why 文章:</strong></p><p><strong><a href="https://waitbutwhy.com/2013/12/how-to-name-baby.html" target="_blank" rel="noreferrer">如何给宝宝取名</a></strong></p><p><strong><a href="https://waitbutwhy.com/2013/12/11-awkward-things-about-email.html" target="_blank" rel="noreferrer">关于电子邮件的 11 件尴尬事</a></strong></p><p><a href="https://waitbutwhy.com/2014/12/the-teen-years-9-cringe-inducing-realizations.html" target="_blank" rel="noreferrer"><strong>我那些让人脚趾抠地的青少年时期</strong></a></p><hr><p>如果你喜欢 Wait But Why,可以订阅我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章发布时我们会发送给你。</p><p>想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><hr><ol><li><p>这整篇文章对不是美国人的读者来说,可能听起来有点神经病。不知道从什么时候开始,美国决定让顾客——而不是雇主——来支付服务员工的工资,从此以后这个系统就一直是个古怪的烂摊子。本文所说的小费全部指美国的小费。<a href="#note-1-1377">↩</a></p></li><li><p>我到现在也不知道为什么,他们自己也不知道。<a href="#note-2-1377">↩</a></p></li><li><p>我的具体访谈都来自曼哈顿,但我的研究表明,以下信息在美国大多数地方都相当准确。<a href="#note-3-1377">↩</a></p></li><li><p>更多细节请见<a href="https://waitbutwhy.com/2014/04/spending-profiles-info.html" target="_blank" rel="noreferrer">这里</a>。<a href="#note-4-1377">↩</a></p></li><li><p>幸运的是,Lynn 的研究还表明,服务员工<em>认为</em>服务质量与小费金额之间存在关联,所以这套激励机制还是奏效的。<a href="#note-5-1377">↩</a></p></li><li><p><a href="http://tippingresearch.com/uploads/Waiter_Survey_Initial_Report__1_.pdf" target="_blank" rel="noreferrer">来源</a> (第 16、17 页)<a href="#note-6-1377">↩</a></p></li><li><p>Lynn, M. (2009). <a href="http://tippingresearch.com/uploads/ServerAppearance1-3-08.pdf" target="_blank" rel="noreferrer">女性吸引力和性感度的决定因素与后果:以餐厅女服务员为对象的现实测试。</a> Archives of Sexual Behavior, 38, 737-745.<a href="#note-7-1377">↩</a></p></li><li><p>Lynn, M., Le, J. &amp; Sherwyn, D. (1998). <a href="http://tippingresearch.com/uploads/Reachout.pdf" target="_blank" rel="noreferrer">伸手去触碰你的顾客。</a> Cornell Hotel and Restaurant Administration Quarterly, 39, 60-65.<a href="#note-8-1377">↩</a></p></li><li><p>Strohmetz, D., Rind, B., Fisher, R. &amp; Lynn, M. (2002). <a href="http://tippingresearch.com/uploads/Candy_Manuscript.pdf" target="_blank" rel="noreferrer">给账单加点糖:用糖果增加餐厅小费。</a> Journal of Applied Social Psychology, 32, 300-309.<a href="#note-9-1377">↩</a></p></li><li><p><a href="http://dash.harvard.edu/handle/1/9491448" target="_blank" rel="noreferrer">Magnus Thor Torfason —— 温馨提示:亲社会性小费与腐败相关</a><a href="#note-10-1377">↩</a></p></li></ol><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2014/04/everything-dont-know-tipping.html&amp;description=Everything%20You%20Don%E2%80%99t%20Know%20About%20Tipping" target="_blank" rel="noreferrer"><img src="'+T+'" alt=""></a></p>',87)])])}const P=r(B,[["render",M]]);export{E as __pageData,P as default};
